const now = new Date();
// Get today's date in GMT (YYYY-MM-DD)
const gmtDate = now.toLocaleDateString('en-CA', { timeZone: 'Europe/London' });

// Compute 'since' = yesterday midnight GMT (to catch all emails from yesterday through now)
const sinceDate = new Date(now);
sinceDate.setDate(sinceDate.getDate() - 1);
sinceDate.setHours(0, 0, 0, 0);
const sinceISO = sinceDate.toISOString();

const inboxes = [
  { address: 'support@syntharra.com',   label: 'Support',   priority: 'high'   },
  { address: 'sales@syntharra.com',      label: 'Sales',     priority: 'high'   },
  { address: 'solutions@syntharra.com',  label: 'Solutions', priority: 'high'   },
  { address: 'alerts@syntharra.com',     label: 'Alerts',    priority: 'high'   },
  { address: 'info@syntharra.com',       label: 'Info',      priority: 'medium' },
  { address: 'admin@syntharra.com',      label: 'Admin',     priority: 'medium' },
  { address: 'careers@syntharra.com',    label: 'Careers',   priority: 'medium' }
];

return inboxes.map(inbox => ({
  json: {
    digest_date: gmtDate,
    since_iso: sinceISO,
    inbox_address: inbox.address,
    inbox_label: inbox.label,
    inbox_priority: inbox.priority
  }
}));

// Get context from previous items
const inbox_address = $('Set Run Context').item.json.inbox_address;
const inbox_label = $('Set Run Context').item.json.inbox_label;
const digest_date = $('Set Run Context').item.json.digest_date;
const inbox_priority = $('Set Run Context').item.json.inbox_priority;

const emails = $input.all();

if (!emails || emails.length === 0) {
  return [{ json: {
    inbox_address, inbox_label, digest_date, inbox_priority,
    emails: [], email_count: 0, has_emails: false
  }}];
}

const prepared = emails.map(item => {
  const msg = item.json;
  const headers = msg.payload?.headers || [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
    return h?.value || '';
  };

  return {
    gmail_id: msg.id,
    thread_id: msg.threadId,
    from_address: getHeader('From'),
    subject: getHeader('Subject') || '(no subject)',
    date_header: getHeader('Date'),
    snippet: msg.snippet ? msg.snippet.substring(0, 500) : '',
    label_ids: msg.labelIds || []
  };
}).filter(e => e.gmail_id);

return [{ json: {
  inbox_address, inbox_label, digest_date, inbox_priority,
  emails: prepared, email_count: prepared.length, has_emails: prepared.length > 0
}}];

const inbox_address = $('Prepare Email Data').item.json.inbox_address;
const inbox_label   = $('Prepare Email Data').item.json.inbox_label;
const digest_date   = $('Prepare Email Data').item.json.digest_date;

const aiResponse = $input.item.json.message?.content || $input.item.json.choices?.[0]?.message?.content || '';

let parsed = [];
try {
  // Strip any markdown code fences
  const clean = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
  if (!Array.isArray(parsed)) parsed = [parsed];
} catch (e) {
  // If JSON fails, return empty (don't crash the whole run)
  console.error('AI parse failed:', e.message, 'Response was:', aiResponse.substring(0, 200));
  return [{ json: { records: [], inbox_address, inbox_label, digest_date, parse_error: e.message } }];
}

// Filter out low importance emails and build Supabase records
const records = parsed
  .filter(e => e && e.gmail_id && e.importance !== 'low')
  .map(e => ({
    digest_date,
    inbox_address,
    inbox_label,
    email_id:       e.gmail_id,
    thread_id:      e.thread_id || null,
    from_address:   e.from_address || '',
    subject:        (e.subject || '(no subject)').substring(0, 500),
    snippet:        (e.snippet || '').substring(0, 500),
    ai_summary:     (e.ai_summary || '').substring(0, 500),
    importance:     ['high','medium','low'].includes(e.importance) ? e.importance : 'medium',
    category:       e.category || 'general',
    action_required: !!e.action_required,
    flag:           ['urgent','opportunity','hire'].includes(e.flag) ? e.flag : null,
    received_at:    e.received_at || null
  }));

return [{ json: { records, inbox_address, inbox_label, digest_date, count: records.length } }];

const { records } = $input.item.json;
if (!records || records.length === 0) return [];
return records.map(r => ({ json: r }));

// Build a human-readable summary of the entire run
const items = $input.all();
let totalSaved = 0;
let inboxesWithContent = 0;
let highPriority = 0;
let actionRequired = 0;

const inboxSummaries = [];

// This node collects summary from all paths that fed into it
// We'll build from what was inserted
for (const item of items) {
  const d = item.json;
  if (d.inbox_address && d.subject) {
    // This is an inserted record
    totalSaved++;
    if (d.importance === 'high') highPriority++;
    if (d.action_required) actionRequired++;
  }
}

const digest_date = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
  timeZone: 'Europe/London'
});

return [{
  json: {
    digest_date,
    total_saved: totalSaved,
    high_priority: highPriority,
    action_required: actionRequired,
    run_completed_at: new Date().toISOString(),
    status: 'completed'
  }
}];
